package org.apache.commons.csv.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.Lexer;
import org.apache.commons.csv.CSVLexer;
import org.apache.commons.csv.Token;
import org.apache.commons.csv.Constants;
import org.apache.commons.csv.ExtendedBufferedReader;
import java.io.StringReader;
import java.io.IOException;

import static org.junit.Assert.assertEquals;

public class StepDefs {

    private Lexer lexer;
    private Token token;

    @Given("I have a CSV lexer configured with escape character {string}")
    public void i_have_a_csv_lexer_configured_with_escape_character(String escapeChar) {
        // We can't easily inject just the escape char into CSVLexer without a format or builder in this version probably.
        // Let's check CSVLexer constructors or CSVFormat.
        // CSVFormat format = CSVFormat.DEFAULT.withEscape(escapeChar.charAt(0));
        // But CSVLexer takes (CSVFormat, ExtendedBufferedReader).
    }

    @When("I tokenize the input string {string}")
    public void i_tokenize_the_input_string(String input) throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('\\');
        ExtendedBufferedReader reader = new ExtendedBufferedReader(new StringReader(input));
        lexer = new CSVLexer(format, reader);
        token = new Token();
        // The instruction says "tokenize", implying we want the content.
        // Token t = lexer.nextToken(new Token());
        token = lexer.nextToken(token);
    }

    @Then("the generated token content should be {string}")
    public void the_generated_token_content_should_be(String expectedContent) {
        assertEquals(expectedContent, token.content.toString());
    }
}

package org.apache.commons.csv;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVLexer;
import org.apache.commons.csv.Token;
import org.apache.commons.csv.ExtendedBufferedReader;
import java.io.StringReader;
import java.io.IOException;

import static org.junit.Assert.assertEquals;

public class StepDefs {

    private CSVLexer lexer;
    private Token token;
    private CSVFormat format;

    @Given("I have a CSV lexer configured with escape character {string}")
    public void i_have_a_csv_lexer_configured_with_escape_character(String escapeChar) {
        if (escapeChar.equals("\\")) {
             this.format = CSVFormat.DEFAULT.withEscape('\\');
        } else {
             this.format = CSVFormat.DEFAULT.withEscape(escapeChar.charAt(0));
        }
    }

    @When("I tokenize the input string {string}")
    public void i_tokenize_the_input_string(String input) throws IOException {
        ExtendedBufferedReader reader = new ExtendedBufferedReader(new StringReader(input));
        lexer = new CSVLexer(format, reader);
        token = new Token();
        token = lexer.nextToken(token);
    }

    @Then("the generated token content should be {string}")
    public void the_generated_token_content_should_be(String expectedContent) {
        assertEquals(expectedContent, token.content.toString());
    }
}

